import React from "react";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Loading/Loading.jsx";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import { useParams } from "react-router-dom";

function ProductsDetails() {
  const { ProductId } = useParams();

  const { data, isLoading, isSuccess, error } = useQuery({
    queryKey: ["productDetails", ProductId],
    queryFn: () =>
      fetch(`http://127.0.0.1:8000/api/ProductDetails/${ProductId}`).then((res) =>
        res.json()
      ),
  });

  if (isLoading) {
    return null; // Let Layout handle the loading state
  }

  if (error) {
    return null; // Let Layout handle the error state
  }

  return (
    isSuccess && (
      <div className="hugy-body">
        <div className="border-container">
          <h1>{data[0].product_name}</h1>
          <Swiper>
            {JSON.parse(data[0].product_images).images.map((image, index) => (
              <SwiperSlide key={index}>
                <img src={image} alt={`Slide ${index}`} />
              </SwiperSlide>
            ))}
          </Swiper>
          <p>{data[0].product_description}</p>
        </div>
      </div>
    )
  );
}

export default ProductsDetails;
